SERVICE <https://klab.ilc.cnr.it/graphdb-compl-it/> {
    ?word a ontolex:Word ;

          ontolex:sense ?sense ;
          ontolex:canonicalForm ?form .
    ?form ontolex:writtenRep ?lemma .
    OPTIONAL {
      ?sense skos:definition ?definition
    } .
    FILTER(str(?lemma) = "capo") .
  }
}

PREFIX lexinfo: <http://www.lexinfo.net/ontology/3.0/lexinfo#>
PREFIX ontolex: <http://www.w3.org/ns/lemon/ontolex#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX skos: <http://www.w3.org/2004/02/skos/core#>

SELECT (COUNT(DISTINCT ?sense) as ?count)
WHERE {
SERVICE <https://klab.ilc.cnr.it/graphdb-compl-it/> {
    ?word a ontolex:Word ;

          ontolex:sense ?sense ;
          ontolex:canonicalForm ?form .
    ?form ontolex:writtenRep ?lemma .
    OPTIONAL {
      ?sense skos:definition ?definition
    } .
    FILTER(str(?lemma) = "fine") .
  }
}

PREFIX ontolex: <http://www.w3.org/ns/lemon/ontolex#>

SELECT ?writtenRep (COUNT(DISTINCT ?sense) as ?count)
WHERE {
SERVICE <https://klab.ilc.cnr.it/graphdb-compl-it/> {
    ?lexicalEntry ontolex:canonicalForm [ ontolex:writtenRep ?writtenRep ] .
    ?lexicalEntry ontolex:sense ?sense .
    FILTER(regex(str(?writtenRep), "^(banco|piano|campo|punto)$", "i"))
  }
}
GROUP BY ?writtenRep
ORDER BY DESC(?count)

PREFIX ontolex: <http://www.w3.org/ns/lemon/ontolex#>

SELECT ?writtenRep (COUNT(DISTINCT ?sense) as ?count)
WHERE {
SERVICE <https://klab.ilc.cnr.it/graphdb-compl-it/> {
    ?lexicalEntry ontolex:canonicalForm [ ontolex:writtenRep ?writtenRep ] .
    ?lexicalEntry ontolex:sense ?sense .
    FILTER(regex(str(?writtenRep), "^(capo|fine|corso)$", "i"))
  }
}
GROUP BY ?writtenRep
ORDER BY DESC(?count)

PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX elita: <http://w3id.org/elita/>
PREFIX lexinfo: <http://www.lexinfo.net/ontology/3.0/lexinfo#>
PREFIX marl: <http://www.gsi.upm.es/ontologies/marl/ns#>
PREFIX ontolex: <http://www.w3.org/ns/lemon/ontolex#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX skos: <http://www.w3.org/2004/02/skos/core#>
PREFIX vartrans: <http://www.w3.org/ns/lemon/vartrans#>

SELECT ?relatedWord ?relatedSense ?definition ?liitaLemma ?sentixLemma ?polarity ?polarityLabel ?polarityValue ?elitaLemma ?emotion ?emotionLabel ?sicilianLemma ?sicilianWR ?complitWord ?sense ?italianWR
WHERE {
SERVICE <https://klab.ilc.cnr.it/graphdb-compl-it/> {
    ?word a ontolex:Word ;
          lexinfo:partOfSpeech [ rdfs:label ?pos ] ;
          ontolex:sense ?sense ;
          ontolex:canonicalForm [ ontolex:writtenRep ?lemma ] .

    ?relatedSense lexinfo:partMeronym ?sense .
    OPTIONAL {
      ?relatedSense skos:definition ?definition
    } .

    FILTER(str(?pos) = "noun") .
    FILTER(str(?lemma) = "veicolo") .

    ?relatedWord ontolex:sense ?relatedSense .
  }
?relatedWord ontolex:canonicalForm ?liitaLemma .
?sentixLemma ontolex:canonicalForm ?liitaLemma .
  ?sentixLemma marl:hasPolarity ?polarity .
  ?polarity rdfs:label ?polarityLabel .
  ?sentixLemma marl:hasPolarityValue ?polarityValue .
?elitaLemma ontolex:canonicalForm ?liitaLemma .
  GRAPH <http://w3id.org/elita> {
    ?elitaLemma elita:HasEmotion ?emotion .
    ?emotion rdfs:label ?emotionLabel .
  }
?lesicilianSic ontolex:canonicalForm ?sicilianLemma .
  ?lesicilianIta vartrans:translatableAs ?lesicilianSic ;
               ontolex:canonicalForm ?liitaLemma .
  ?sicilianLemma dcterms:isPartOf <http://liita.it/data/id/DialettoSiciliano/lemma/LemmaBank> ;
                  ontolex:writtenRep ?sicilianWR .
?complitWord a ontolex:Word ;
          ontolex:sense ?sense ;
          ontolex:canonicalForm ?liitaLemma .
  OPTIONAL {
    ?sense skos:definition ?definition
  } .
?liitaLemma ontolex:writtenRep ?italianWR .
}

PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX elita: <http://w3id.org/elita/>
PREFIX lexinfo: <http://www.lexinfo.net/ontology/3.0/lexinfo#>
PREFIX lila: <http://lila-erc.eu/ontologies/lila/>
PREFIX marl: <http://www.gsi.upm.es/ontologies/marl/ns#>
PREFIX ontolex: <http://www.w3.org/ns/lemon/ontolex#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX skos: <http://www.w3.org/2004/02/skos/core#>
PREFIX vartrans: <http://www.w3.org/ns/lemon/vartrans#>

SELECT ?lemma ?wr ?sentixLemma ?polarity ?polarityLabel ?polarityValue ?elitaLemma ?emotion ?emotionLabel ?sicilianLemma ?sicilianWR ?complitWord ?sense ?definition
WHERE {
GRAPH <http://liita.it/data> {
    ?lemma a lila:Lemma ;
           ontolex:writtenRep ?wr .
    ?lemma lila:hasPOS lila:noun .
    FILTER(strstarts(str(?wr), "gioi")) .
  }
?sentixLemma ontolex:canonicalForm ?lemma .
  ?sentixLemma marl:hasPolarity ?polarity .
  ?polarity rdfs:label ?polarityLabel .
  ?sentixLemma marl:hasPolarityValue ?polarityValue .
  FILTER(strstarts(str(?wr), "gioi")) .
  FILTER(?emotion = elita:Gioia) .
VALUES ?emotion { elita:Gioia }
  ?elitaLemma ontolex:canonicalForm ?lemma .
  GRAPH <http://w3id.org/elita> {
    ?elitaLemma elita:HasEmotion ?emotion .
    ?emotion rdfs:label ?emotionLabel .
  }

  FILTER(strstarts(str(?wr), "gioi")) .
?lesicilianSic ontolex:canonicalForm ?sicilianLemma .
  ?lesicilianIta vartrans:translatableAs ?lesicilianSic ;
               ontolex:canonicalForm ?lemma .
  ?sicilianLemma dcterms:isPartOf <http://liita.it/data/id/DialettoSiciliano/lemma/LemmaBank> ;
                  ontolex:writtenRep ?sicilianWR .
?complitWord a ontolex:Word ;
          lexinfo:partOfSpeech [ rdfs:label ?complitPos ] ;
          ontolex:sense ?sense ;
          ontolex:canonicalForm ?lemma .
  OPTIONAL {
    ?sense skos:definition ?definition
  } .
    FILTER(str(?complitPos) = "noun") .
}
